  framework: shell;
}

workflow[name="install"] {
  trigger: manual;
  step-1: run cmd=make install;
}

workflow[name="dev"] {
  trigger: manual;
  step-1: run cmd=make;
}

workflow[name="build"] {
  trigger: manual;
  step-1: run cmd=make build;
}

workflow[name="test"] {
  trigger: manual;
  step-1: run cmd=make test;
}

workflow[name="lint"] {
  trigger: manual;
  step-1: run cmd=make lint;
}

workflow[name="fmt"] {
  trigger: manual;
  step-1: run cmd=make fmt;
}

workflow[name="clean"] {
  trigger: manual;
  step-1: run cmd=make clean;
}

workflow[name="help"] {
  trigger: manual;
  step-1: run cmd=task --list;
}

deploy {
  target: binary;
}

environment[name="local"] {
  runtime: shell;
}
